    {
        public string Url { get; set; } = "";
        public string Title { get; set; } = "";
        public string Snippet { get; set; } = "";
    }
}

/// <summary>A simple notepad tool for the agent to record and retrieve findings.</summary>
sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note. Use this to record key findings, facts, or quotes as you research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [note] Saved note #{_notes.Count} ({note.Length} chars)");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all saved research notes. Call this before writing your final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  [notes] Retrieving {_notes.Count} note(s)");
        return string.Join("\n\n", _notes.Select((n, i) => $"--- Note {i + 1} ---\n{n}"));
    }
}

