+        Console.WriteLine($"  [note] Saved note #{_notes.Count} ({note.Length} chars)");
+        return $"Note #{_notes.Count} saved successfully.";
+    }
+
+    [Description("Retrieves all saved research notes. Call this before writing your final summary.")]
+    public string GetNotes()
+    {
+        if (_notes.Count == 0)
+            return "No notes saved yet.";
+
+        Console.WriteLine($"  [notes] Retrieving {_notes.Count} note(s)");
+        return string.Join("\n\n", _notes.Select((n, i) => $"--- Note {i + 1} ---\n{n}"));
+    }
+}

